import json
import boto3
from datetime import datetime

def lambda_handler(event, context):
    user_data = {
        'users': [
            {
                'id': 1,
                'name': 'John Doe',
                'email': 'john@example.com',
                'role': 'admin',
                'created_at': '2024-01-15T10:30:00Z'
            },
            {
                'id': 2,
                'name': 'Jane Smith',
                'email': 'jane@example.com',
                'role': 'user',
                'created_at': '2024-01-16T14:20:00Z'
            },
            {
                'id': 3,
                'name': 'Bob Johnson',
                'email': 'bob@example.com',
                'role': 'user',
                'created_at': '2024-01-17T09:15:00Z'
            }
        ],
        'timestamp': datetime.utcnow().isoformat() + 'Z',
        'total_count': 3
    }
    
    response = {
        'statusCode': 200,
        'headers': {
            'Content-Type': 'application/json',
            'Access-Control-Allow-Origin': '*',
            'Access-Control-Allow-Headers': 'Content-Type,X-Amz-Date,Authorization,X-Api-Key,X-Amz-Security-Token',
            'Access-Control-Allow-Methods': 'GET,POST,PUT,DELETE,OPTIONS',
            'Access-Control-Allow-Credentials': 'true'
        },
        'body': json.dumps(user_data)
    }
    
    if event.get('httpMethod') == 'OPTIONS':
        return response
    
    if event.get('httpMethod') == 'GET':
        path_parameters = event.get('pathParameters', {})
        query_parameters = event.get('queryStringParameters', {})
        
        if path_parameters and path_parameters.get('userId'):
            user_id = int(path_parameters['userId'])
            user = next((u for u in user_data['users'] if u['id'] == user_id), None)
            
            if user:
                response['body'] = json.dumps({
                    'user': user,
                    'timestamp': user_data['timestamp']
                })
            else:
                response['statusCode'] = 404
                response['body'] = json.dumps({'error': 'User not found'})
        
        elif query_parameters and query_parameters.get('role'):
            role = query_parameters['role']
            filtered_users = [u for u in user_data['users'] if u['role'] == role]
            response['body'] = json.dumps({
                'users': filtered_users,
                'timestamp': user_data['timestamp'],
                'total_count': len(filtered_users)
            })
    
    elif event.get('httpMethod') == 'POST':
        try:
            body = json.loads(event.get('body', '{}'))
            new_user = {
                'id': len(user_data['users']) + 1,
                'name': body.get('name', ''),
                'email': body.get('email', ''),
                'role': body.get('role', 'user'),
                'created_at': datetime.utcnow().isoformat() + 'Z'
            }
            response['statusCode'] = 201
            response['body'] = json.dumps({
                'message': 'User created successfully',
                'user': new_user
            })
        except Exception as e:
            response['statusCode'] = 400
            response['body'] = json.dumps({'error': str(e)})
    
    return response